  ('heelevel3-1fb53453-moex-00341', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-110-3082b5f1', 'sub-heelevel3-1fb53453-02', NULL, 'single_choice', '當人民提起課予義務訴訟，而行政法院認為行政機關之不作為雖屬違法，但就人民所請求之行政 處分的作成行政機關尚有裁量空間時，應如何裁判？', '["以判決命行政機關作成原告所申請內容之行政處分", "以原告之訴無理由，判決駁回", "以判決命行政機關遵照判決之法律見解對於原告作成處分", "以原告之訴不合法，裁定駁回"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:30+00:00", "source_pdf_sha1": "b59c20af004e", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "330", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財經廉政"}'::jsonb, NULL),
